  "seo.title": "CallMyProf - \u0627\u0639\u062B\u0631 \u0639\u0644\u0649 \u0645\u0639\u0644\u0651\u0645\u0643 \u0627\u0644\u0645\u062B\u0627\u0644\u064A | \u062F\u0631\u0648\u0633 \u062E\u0635\u0648\u0635\u064A\u0629 \u0628\u0623\u0633\u0639\u0627\u0631 \u0645\u0639\u0642\u0648\u0644\u0629",
  "seo.description": "\u062F\u0631\u0648\u0633 \u062E\u0635\u0648\u0635\u064A\u0629 \u0628\u0623\u0633\u0639\u0627\u0631 \u0645\u0639\u0642\u0648\u0644\u0629 \u0627\u0628\u062A\u062F\u0627\u0621\u064B \u0645\u0646 15$/\u0633\u0627\u0639\u0629. \u0645\u0639\u0644\u0651\u0645\u0648\u0646 \u062E\u0628\u0631\u0627\u0621 \u0641\u064A \u0627\u0644\u0631\u064A\u0627\u0636\u064A\u0627\u062A \u0648\u0627\u0644\u0639\u0644\u0648\u0645 \u0648\u0627\u0644\u0644\u063A\u0627\u062A \u0648\u0627\u0644\u0645\u0648\u0633\u064A\u0642\u0649. \u0646\u062A\u0635\u0644 \u0628\u0643 \u062E\u0644\u0627\u0644 24 \u0633\u0627\u0639\u0629.",
  "seo.og_title": "CallMyProf - \u062F\u0631\u0648\u0633 \u062E\u0635\u0648\u0635\u064A\u0629 \u0628\u0623\u0633\u0639\u0627\u0631 \u0645\u0639\u0642\u0648\u0644\u0629",
  "seo.og_description": "\u0627\u0639\u062B\u0631 \u0639\u0644\u0649 \u0645\u0639\u0644\u0651\u0645\u0643 \u0627\u0644\u0645\u062B\u0627\u0644\u064A \u0627\u0628\u062A\u062F\u0627\u0621\u064B \u0645\u0646 15$/\u0633\u0627\u0639\u0629. \u0645\u0639\u0644\u0651\u0645\u0648\u0646 \u0645\u0624\u0647\u0644\u0648\u0646\u060C \u0645\u0648\u0627\u0639\u064A\u062F \u0645\u0631\u0646\u0629\u060C \u0646\u062A\u0627\u0626\u062C \u0645\u062B\u0628\u062A\u0629.",
