  // ---- About ----
  "about.page_title": "\u0645\u0646 \u0646\u062D\u0646",
  "about.hero_title": "\u0639\u0646 CallMyProf",
  "about.hero_subtitle": "\u062C\u0639\u0644 \u0627\u0644\u062A\u0639\u0644\u064A\u0645 \u0627\u0644\u062C\u064A\u062F \u0645\u062A\u0627\u062D\u064B\u0627 \u0648\u0628\u0623\u0633\u0639\u0627\u0631 \u0645\u0639\u0642\u0648\u0644\u0629 \u0644\u0644\u062C\u0645\u064A\u0639.",
  "about.mission_title": "\u0645\u0647\u0645\u062A\u0646\u0627",
  "about.mission_text": "\u062A\u0623\u0633\u0633 CallMyProf \u0628\u0641\u0643\u0631\u0629 \u0628\u0633\u064A\u0637\u0629: \u0643\u0644 \u0637\u0627\u0644\u0628 \u064A\u0633\u062A\u062D\u0642 \u062F\u0631\u0648\u0633\u064B\u0627 \u062E\u0635\u0648\u0635\u064A\u0629 \u0639\u0627\u0644\u064A\u0629 \u0627\u0644\u062C\u0648\u062F\u0629\u060C \u0628\u063A\u0636 \u0627\u0644\u0646\u0638\u0631 \u0639\u0646 \u0645\u064A\u0632\u0627\u0646\u064A\u062A\u0647. \u0646\u062D\u0646 \u0646\u0631\u0628\u0637 \u0627\u0644\u0637\u0644\u0627\u0628 \u0648\u0627\u0644\u0639\u0627\u0626\u0644\u0627\u062A \u0628\u0645\u0639\u0644\u0651\u0645\u064A\u0646 \u0645\u0624\u0647\u0644\u064A\u0646 \u0648\u0634\u063A\u0648\u0641\u064A\u0646.",
  "about.mission_quote": "\u0646\u0624\u0645\u0646 \u0628\u0623\u0646 \u0627\u0644\u062A\u0639\u0644\u064A\u0645 \u0647\u0648 \u0623\u0642\u0648\u0649 \u0623\u062F\u0627\u0629 \u0644\u062A\u063A\u064A\u064A\u0631 \u0627\u0644\u062D\u064A\u0627\u0629. \u0645\u0647\u0645\u062A\u0646\u0627 \u062C\u0639\u0644\u0647 \u0645\u062A\u0627\u062D\u064B\u0627 \u0644\u0644\u062C\u0645\u064A\u0639.",
  "about.values_title": "\u0642\u064A\u0645\u0646\u0627",
  "about.value1_title": "\u0627\u0644\u062C\u0648\u062F\u0629 \u0623\u0648\u0644\u0627\u064B",
  "about.value1_desc": "\u0643\u0644 \u0645\u0639\u0644\u0651\u0645 \u064A\u062E\u0636\u0639 \u0644\u0641\u062D\u0635 \u062F\u0642\u064A\u0642 \u0648\u062A\u062F\u0631\u064A\u0628 \u0644\u0636\u0645\u0627\u0646 \u0623\u0639\u0644\u0649 \u0645\u0633\u062A\u0648\u0649 \u062A\u0639\u0644\u064A\u0645.",
  "about.value2_title": "\u0623\u0633\u0639\u0627\u0631 \u0645\u0639\u0642\u0648\u0644\u0629",
  "about.value2_desc": "\u0627\u0628\u062A\u062F\u0627\u0621\u064B \u0645\u0646 15$/\u0633\u0627\u0639\u0629\u060C \u0646\u062C\u0639\u0644 \u0627\u0644\u062F\u0631\u0648\u0633 \u0627\u0644\u062E\u0635\u0648\u0635\u064A\u0629 \u0645\u062A\u0627\u062D\u0629 \u0644\u0643\u0644 \u0639\u0627\u0626\u0644\u0629.",
  "about.value3_title": "\u0627\u0646\u062A\u0634\u0627\u0631 \u0639\u0627\u0644\u0645\u064A",
  "about.value3_desc": "\u0645\u062A\u0627\u062D \u0628\u0627\u0644\u0625\u0646\u062C\u0644\u064A\u0632\u064A\u0629 \u0648\u0627\u0644\u0641\u0631\u0646\u0633\u064A\u0629 \u0648\u0627\u0644\u0639\u0631\u0628\u064A\u0629\u060C \u0646\u062E\u062F\u0645 \u0627\u0644\u0637\u0644\u0627\u0628 \u062D\u0648\u0644 \u0627\u0644\u0639\u0627\u0644\u0645.",
  "about.value4_title": "\u0644\u0645\u0633\u0629 \u0634\u062E\u0635\u064A\u0629",
  "about.value4_desc": "\u0646\u062A\u0635\u0644 \u0628\u0643 \u0634\u062E\u0635\u064A\u064B\u0627 \u0644\u0641\u0647\u0645 \u0627\u062D\u062A\u064A\u0627\u062C\u0627\u062A\u0643 \u0642\u0628\u0644 \u0627\u0642\u062A\u0631\u0627\u062D \u0645\u0639\u0644\u0651\u0645.",
  "about.how_title": "\u0643\u064A\u0641 \u0646\u0639\u0645\u0644",
  "about.how_step1_title": "\u062A\u062A\u0648\u0627\u0635\u0644 \u0645\u0639\u0646\u0627",
  "about.how_step1_desc": "\u0627\u0645\u0644\u0623 \u0646\u0645\u0648\u0630\u062C\u064B\u0627 \u0633\u0631\u064A\u0639\u064B\u0627 \u0644\u0625\u062E\u0628\u0627\u0631\u0646\u0627 \u0628\u0645\u0627 \u062A\u062D\u062A\u0627\u062C.",
  "about.how_step2_title": "\u0646\u062A\u0635\u0644 \u0628\u0643",
