  "terms.last_updated": "\u0622\u062E\u0631 \u062A\u062D\u062F\u064A\u062B: \u0645\u0627\u0631\u0633 2026",
  "terms.s1_title": "\u0642\u0628\u0648\u0644 \u0627\u0644\u0634\u0631\u0648\u0637",
  "terms.s1_text": "\u0628\u0627\u0633\u062A\u062E\u062F\u0627\u0645 \u062E\u062F\u0645\u0627\u062A CallMyProf\u060C \u0641\u0625\u0646\u0643 \u062A\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u0627\u0644\u0627\u0644\u062A\u0632\u0627\u0645 \u0628\u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637.",
  "terms.s2_title": "\u0648\u0635\u0641 \u0627\u0644\u062E\u062F\u0645\u0627\u062A",
  "terms.s2_text": "CallMyProf \u0645\u0646\u0635\u0629 \u062A\u0631\u0628\u0637 \u0627\u0644\u0637\u0644\u0627\u0628 \u0648\u0627\u0644\u0639\u0627\u0626\u0644\u0627\u062A \u0628\u0645\u0639\u0644\u0651\u0645\u064A\u0646 \u0645\u0624\u0647\u0644\u064A\u0646. \u0646\u0633\u0647\u0651\u0644 \u0627\u0644\u062A\u0648\u0641\u064A\u0642 \u0648\u0627\u0644\u062C\u062F\u0648\u0644\u0629 \u0648\u0627\u0644\u062F\u0641\u0639.",
  "terms.s3_title": "\u0645\u0633\u0624\u0648\u0644\u064A\u0627\u062A \u0627\u0644\u0645\u0633\u062A\u062E\u062F\u0645",
  "terms.s3_text": "\u0643\u0645\u0633\u062A\u062E\u062F\u0645\u060C \u062A\u0648\u0627\u0641\u0642 \u0639\u0644\u0649:",
  "terms.s3_item1": "\u062A\u0642\u062F\u064A\u0645 \u0645\u0639\u0644\u0648\u0645\u0627\u062A \u062F\u0642\u064A\u0642\u0629 \u0648\u0643\u0627\u0645\u0644\u0629.",
  "terms.s3_item2": "\u0645\u0639\u0627\u0645\u0644\u0629 \u0627\u0644\u0645\u0639\u0644\u0651\u0645\u064A\u0646 \u0628\u0627\u062D\u062A\u0631\u0627\u0645.",
  "terms.s3_item3": "\u0627\u0644\u062F\u0641\u0639 \u0641\u064A \u0627\u0644\u0648\u0642\u062A \u0627\u0644\u0645\u062D\u062F\u062F.",
  "terms.s4_title": "\u0627\u0644\u0639\u0644\u0627\u0642\u0629 \u0645\u0639 \u0627\u0644\u0645\u0639\u0644\u0651\u0645\u064A\u0646",
  "terms.s4_text": "\u0627\u0644\u0645\u0639\u0644\u0651\u0645\u0648\u0646 \u0645\u0642\u0627\u0648\u0644\u0648\u0646 \u0645\u0633\u062A\u0642\u0644\u0648\u0646. CallMyProf \u064A\u0633\u0647\u0651\u0644 \u0627\u0644\u062A\u0648\u0627\u0635\u0644 \u0644\u0643\u0646\u0647 \u063A\u064A\u0631 \u0645\u0633\u0624\u0648\u0644 \u0639\u0646 \u062C\u0648\u062F\u0629 \u0627\u0644\u062A\u062F\u0631\u064A\u0633.",
  "terms.s5_title": "\u0627\u0644\u0645\u062F\u0641\u0648\u0639\u0627\u062A \u0648\u0627\u0644\u0627\u0633\u062A\u0631\u062F\u0627\u062F",
  "terms.s5_text": "\u0627\u0644\u0645\u062F\u0641\u0648\u0639\u0627\u062A \u062A\u062A\u0645 \u0628\u0634\u0643\u0644 \u0622\u0645\u0646. \u064A\u0645\u0643\u0646 \u0637\u0644\u0628 \u0627\u0633\u062A\u0631\u062F\u0627\u062F \u062E\u0644\u0627\u0644 48 \u0633\u0627\u0639\u0629 \u0645\u0646 \u0627\u0644\u062C\u0644\u0633\u0629.",
  "terms.s6_title": "\u0633\u064A\u0627\u0633\u0629 \u0627\u0644\u0625\u0644\u063A\u0627\u0621",
  "terms.s6_text": "\u064A\u0645\u0643\u0646 \u0625\u0644\u063A\u0627\u0621 \u0627\u0644\u062C\u0644\u0633\u0627\u062A \u0642\u0628\u0644 24 \u0633\u0627\u0639\u0629 \u0628\u062F\u0648\u0646 \u0631\u0633\u0648\u0645. \u0627\u0644\u0625\u0644\u063A\u0627\u0621 \u0627\u0644\u0645\u062A\u0623\u062E\u0631 \u0642\u062F \u064A\u062A\u0631\u062A\u0628 \u0639\u0644\u064A\u0647 \u0631\u0633\u0648\u0645.",
  "terms.s7_title": "\u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u0627\u0644\u0641\u0643\u0631\u064A\u0629",
  "terms.s7_text": "\u0643\u0644 \u0645\u062D\u062A\u0648\u0649 callmyprof.com \u0645\u0644\u0643 \u0644\u0640 CallMyProf \u0648\u0645\u062D\u0645\u064A \u0628\u0642\u0648\u0627\u0646\u064A\u0646 \u0627\u0644\u0645\u0644\u0643\u064A\u0629 \u0627\u0644\u0641\u0643\u0631\u064A\u0629.",
  "terms.s8_title": "\u062A\u062D\u062F\u064A\u062F \u0627\u0644\u0645\u0633\u0624\u0648\u0644\u064A\u0629",
