  "terms.s9_title": "\u0627\u062A\u0635\u0644 \u0628\u0646\u0627",
  "terms.s9_text": "\u0644\u0644\u0623\u0633\u0626\u0644\u0629 \u062D\u0648\u0644 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637\u060C \u062A\u0648\u0627\u0635\u0644 \u0645\u0639\u0646\u0627 \u0639\u0644\u0649:",
  "terms.s10_title": "\u0627\u0644\u0642\u0627\u0646\u0648\u0646 \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647",
  "terms.s10_text": "\u062A\u062E\u0636\u0639 \u0647\u0630\u0647 \u0627\u0644\u0634\u0631\u0648\u0637 \u0644\u0644\u0642\u0627\u0646\u0648\u0646 \u0627\u0644\u062A\u062C\u0627\u0631\u064A \u0627\u0644\u062F\u0648\u0644\u064A \u0627\u0644\u0645\u0639\u0645\u0648\u0644 \u0628\u0647. CallMyProf \u0639\u0644\u0627\u0645\u0629 \u062A\u062C\u0627\u0631\u064A\u0629 \u062A\u062F\u064A\u0631\u0647\u0627 Capleb SAL.",
