  "privacy.s3_text": "\u0644\u0627 \u0646\u0628\u064A\u0639 \u0628\u064A\u0627\u0646\u0627\u062A\u0643. \u0646\u0634\u0627\u0631\u0643\u0647\u0627 \u0641\u0642\u0637 \u0645\u0639 \u0627\u0644\u0645\u0639\u0644\u0651\u0645\u064A\u0646 \u0648\u0645\u0639\u0627\u0644\u062C\u064A \u0627\u0644\u062F\u0641\u0639 \u0648\u0639\u0646\u062F \u0627\u0644\u0637\u0644\u0628 \u0627\u0644\u0642\u0627\u0646\u0648\u0646\u064A.",
  "privacy.s4_title": "\u0623\u0645\u0627\u0646 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A",
  "privacy.s4_text": "\u0646\u0633\u062A\u062E\u062F\u0645 \u0625\u062C\u0631\u0627\u0621\u0627\u062A \u0623\u0645\u0627\u0646 \u0645\u062A\u0648\u0627\u0641\u0642\u0629 \u0645\u0639 \u0645\u0639\u0627\u064A\u064A\u0631 \u0627\u0644\u0635\u0646\u0627\u0639\u0629. \u0643\u0644\u0645\u0627\u062A \u0627\u0644\u0645\u0631\u0648\u0631 \u0645\u0634\u0641\u0651\u0631\u0629 \u0628\u0640 PBKDF2. \u0643\u0644 \u0627\u0644\u0628\u064A\u0627\u0646\u0627\u062A \u062A\u0646\u0642\u0644 \u0639\u0628\u0631 HTTPS.",
  "privacy.s5_title": "\u0645\u0644\u0641\u0627\u062A \u062A\u0639\u0631\u064A\u0641 \u0627\u0644\u0627\u0631\u062A\u0628\u0627\u0637",
