  "faq.page_title": "\u0627\u0644\u0623\u0633\u0626\u0644\u0629 \u0627\u0644\u0634\u0627\u0626\u0639\u0629",
  "faq.hero_title": "\u0627\u0644\u0623\u0633\u0626\u0644\u0629 \u0627\u0644\u0634\u0627\u0626\u0639\u0629",
  "faq.hero_subtitle": "\u0627\u0628\u062D\u062B \u0639\u0646 \u0625\u062C\u0627\u0628\u0627\u062A \u0644\u0623\u0643\u062B\u0631 \u0627\u0644\u0623\u0633\u0626\u0644\u0629 \u0634\u064A\u0648\u0639\u064B\u0627 \u062D\u0648\u0644 CallMyProf.",
  "faq.section_general": "\u0639\u0627\u0645",
  "faq.q1": "\u0645\u0627 \u0647\u0648 CallMyProf\u061F",
  "faq.a1": "CallMyProf \u064A\u0631\u0628\u0637 \u0627\u0644\u0637\u0644\u0627\u0628 \u0648\u0627\u0644\u0639\u0627\u0626\u0644\u0627\u062A \u0628\u0645\u0639\u0644\u0651\u0645\u064A\u0646 \u0645\u0624\u0647\u0644\u064A\u0646. \u0627\u0645\u0644\u0623 \u0627\u0644\u0646\u0645\u0648\u0630\u062C\u060C \u0646\u062A\u0635\u0644 \u0628\u0643\u060C \u0648\u0646\u062C\u062F \u0644\u0643 \u0627\u0644\u0645\u0639\u0644\u0651\u0645 \u0627\u0644\u0645\u062B\u0627\u0644\u064A.",
  "faq.q2": "\u0643\u064A\u0641 \u064A\u0639\u0645\u0644 \u0646\u0638\u0627\u0645 \u0627\u0644\u0627\u062A\u0635\u0627\u0644\u061F",
  "faq.a2": "\u0627\u0645\u0644\u0623 \u0627\u0644\u0646\u0645\u0648\u0630\u062C. \u0645\u0633\u062A\u0634\u0627\u0631 \u064A\u062A\u0635\u0644 \u0628\u0643 \u062E\u0644\u0627\u0644 24 \u0633\u0627\u0639\u0629 \u0644\u0645\u0646\u0627\u0642\u0634\u0629 \u0627\u062D\u062A\u064A\u0627\u062C\u0627\u062A\u0643.",
  "faq.q3": "\u0645\u0627 \u0627\u0644\u0645\u0648\u0627\u062F \u0627\u0644\u062A\u064A \u062A\u0642\u062F\u0645\u0648\u0646\u0647\u0627\u061F",
  "faq.a3": "\u0627\u0644\u0631\u064A\u0627\u0636\u064A\u0627\u062A\u060C \u0627\u0644\u0639\u0644\u0648\u0645\u060C \u0627\u0644\u0644\u063A\u0627\u062A\u060C \u0627\u0644\u0645\u0648\u0633\u064A\u0642\u0649\u060C \u0627\u0644\u062D\u0627\u0633\u0648\u0628\u060C \u0627\u0644\u0641\u0646\u0648\u0646\u060C \u0627\u0644\u0631\u064A\u0627\u0636\u0629\u060C \u0627\u0644\u062A\u062D\u0636\u064A\u0631 \u0644\u0644\u0627\u0645\u062A\u062D\u0627\u0646\u0627\u062A\u060C \u0648\u062F\u0639\u0645 \u0645\u062A\u062E\u0635\u0635.",
  "faq.section_pricing": "\u0627\u0644\u0623\u0633\u0639\u0627\u0631 \u0648\u0627\u0644\u062F\u0641\u0639",
  "faq.q4": "\u0643\u0645 \u062A\u0643\u0644\u0641 \u0627\u0644\u062F\u0631\u0648\u0633\u061F",
  "faq.a4": "\u0641\u0631\u062F\u064A: \u0645\u0646 15$/\u0633\u0627\u0639\u0629. \u062C\u0645\u0627\u0639\u064A: \u0645\u0646 8$/\u0633\u0627\u0639\u0629. \u0623\u0648\u0646\u0644\u0627\u064A\u0646: \u0645\u0646 12$/\u0633\u0627\u0639\u0629.",
  "faq.q5": "\u0645\u0627 \u0637\u0631\u0642 \u0627\u0644\u062F\u0641\u0639 \u0627\u0644\u0645\u0642\u0628\u0648\u0644\u0629\u061F",
  "faq.a5": "\u0628\u0637\u0627\u0642\u0627\u062A \u0627\u0644\u0627\u0626\u062A\u0645\u0627\u0646 \u0639\u0628\u0631 Stripe \u0648PayPal. \u062C\u0645\u064A\u0639 \u0627\u0644\u0645\u062F\u0641\u0648\u0639\u0627\u062A \u0622\u0645\u0646\u0629.",
  "faq.q6": "\u0647\u0644 \u0647\u0646\u0627\u0643 \u0627\u0644\u062A\u0632\u0627\u0645\u061F",
  "faq.a6": "\u0644\u0627 \u0627\u0644\u062A\u0632\u0627\u0645! \u0627\u062D\u062C\u0632 \u062C\u0644\u0633\u0629 \u0628\u062C\u0644\u0633\u0629 \u0623\u0648 \u0627\u0634\u062A\u0631\u0650 \u0628\u0627\u0642\u0629. \u0623\u0644\u063A\u0650 \u0641\u064A \u0623\u064A \u0648\u0642\u062A \u0645\u0639 \u0625\u0634\u0639\u0627\u0631 24 \u0633\u0627\u0639\u0629.",
  "faq.section_tutors": "\u0645\u0639\u0644\u0651\u0645\u0648\u0646\u0627",
  "faq.q7": "\u0643\u064A\u0641 \u064A\u062A\u0645 \u0627\u062E\u062A\u064A\u0627\u0631 \u0627\u0644\u0645\u0639\u0644\u0651\u0645\u064A\u0646\u061F",
  "faq.a7": "\u064A\u062E\u0636\u0639 \u0627\u0644\u0645\u0639\u0644\u0651\u0645\u0648\u0646 \u0644\u0644\u062A\u062D\u0642\u0642 \u0645\u0646 \u0627\u0644\u0634\u0647\u0627\u062F\u0627\u062A \u0648\u062C\u0644\u0633\u0629 \u062A\u062C\u0631\u064A\u0628\u064A\u0629. \u0646\u0642\u0628\u0644 \u0641\u0642\u0637 \u0627\u0644\u0623\u0641\u0636\u0644.",
