var CSS_ANIMATIONS = `
  /* ---- Keyframes ---- */
  @keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
  }

  @keyframes slideUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
  }

  @keyframes slideDown {
    from { opacity: 0; transform: translateY(-10px); }
    to { opacity: 1; transform: translateY(0); }
  }

  @keyframes slideInLeft {
    from { opacity: 0; transform: translateX(-20px); }
    to { opacity: 1; transform: translateX(0); }
  }

  @keyframes pulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.05); }
  }

  @keyframes shimmer {
    0% { background-position: -200% 0; }
    100% { background-position: 200% 0; }
  }

  @keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
  }

  @keyframes bounceIn {
    0% { opacity: 0; transform: scale(0.3); }
    50% { opacity: 1; transform: scale(1.05); }
    70% { transform: scale(0.95); }
    100% { transform: scale(1); }
  }

  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-6px); }
  }

  /* ---- Animation utilities ---- */
  .animate-fadeIn { animation: fadeIn 0.4s ease both; }
  .animate-slideUp { animation: slideUp 0.5s ease both; }
  .animate-slideDown { animation: slideDown 0.3s ease both; }
  .animate-pulse { animation: pulse 2s ease-in-out infinite; }
  .animate-bounceIn { animation: bounceIn 0.6s ease both; }
  .animate-float { animation: float 3s ease-in-out infinite; }

  /* ---- Stagger animation for cards ---- */
  .card { animation: slideUp 0.5s ease both; }
  .card:nth-child(1) { animation-delay: 0.05s; }
  .card:nth-child(2) { animation-delay: 0.1s; }
  .card:nth-child(3) { animation-delay: 0.15s; }
  .card:nth-child(4) { animation-delay: 0.2s; }
  .card:nth-child(5) { animation-delay: 0.25s; }
  .card:nth-child(6) { animation-delay: 0.3s; }
  .card:nth-child(7) { animation-delay: 0.35s; }
  .card:nth-child(8) { animation-delay: 0.4s; }

  /* ---- Hover transforms ---- */
  .hover-lift {
    transition: transform var(--transition-normal), box-shadow var(--transition-normal);
  }
  .hover-lift:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-lg);
  }

  .hover-scale {
    transition: transform var(--transition-fast);
  }
  .hover-scale:hover {
    transform: scale(1.03);
  }

  .hover-glow {
    transition: box-shadow var(--transition-normal);
  }
  .hover-glow:hover {
    box-shadow: 0 0 20px rgba(220, 38, 38, 0.3);
  }

  /* ---- Smooth transitions on all interactive elements ---- */
  button, a, input, select, textarea, .btn, .card, .sidebar-link {
    transition: all var(--transition-fast);
  }

  /* ---- Loading spinner ---- */
  .spinner {
    width: 20px;
    height: 20px;
    border: 2px solid var(--gray-200);
    border-top-color: var(--primary);
    border-radius: 50%;
    animation: spin 0.6s linear infinite;
    display: inline-block;
  }

  /* ---- Notification badge pulse ---- */
  .notification-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 20px;
    height: 20px;
    padding: 0 6px;
    border-radius: 10px;
    background: var(--danger);
    color: var(--white);
    font-size: 11px;
    font-weight: 700;
    animation: pulse 2s ease-in-out infinite;
  }
`;
