function renderLoginPage(error, locale = "en") {
  const errorHtml = error ? `<div class="login-error">
        <span class="error-icon">&#9888;</span>
        <span>${error}</span>
      </div>` : "";
  const particles = Array.from({ length: 20 }, (_, i) => {
    const size = 4 + i % 5 * 6;
    const left = (i * 5.3 + 7) % 100;
    const delay = i * 1.7 % 12;
    const duration = 8 + i % 7 * 3;
    const color = i % 2 === 0 ? "#DC2626" : "#ffffff";
    return `<div class="particle" style="width:${size}px;height:${size}px;left:${left}%;background:${color};animation-delay:${delay}s;animation-duration:${duration}s;"></div>`;
  }).join("\n    ");
  const icons = ["&#128218;", "&#9999;", "&#127891;", "&#128300;", "&#128202;", "&#128640;", "&#128161;", "&#127793;", "&#9733;", "&#128187;", "&#127752;", "&#128290;"];
  const floatingIcons = icons.map((icon, i) => {
    const left = (i * 8.5 + 3) % 100;
    const delay = (i * 2.1 + 0.5) % 15;
    const duration = 12 + i % 5 * 4;
    const size = 24 + i % 3 * 10;
    return `<div class="floating-icon" style="left:${left}%;font-size:${size}px;animation-delay:${delay}s;animation-duration:${duration}s;">${icon}</div>`;
  }).join("\n    ");
  return `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${t(locale, "login.title")} - CallMyProf</title>
  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet">
  <style>
    ${CSS_VARS}
    ${CSS_BASE}
    ${CSS_ANIMATIONS}
    ${LOGIN_CSS}
  </style>
</head>
<body>
  <!-- Animated background particles -->
  <div class="particles">
    ${particles}
  </div>

  <!-- Floating education icons -->
  <div class="floating-icons">
    ${floatingIcons}
  </div>

  <div class="login-wrapper">
    <div class="login-card">
      <div class="login-header">
        <div class="login-logo">&#128222;</div>
        <h1 class="login-title">CallMyProf</h1>
        <p class="login-subtitle">${t(locale, "login.title")}</p>
      </div>

      <form class="login-form" method="POST" action="/login" id="loginForm">
        ${errorHtml}

        <div class="field-group">
          <label class="field-label" for="email">${t(locale, "login.email")}</label>
          <div class="field-input-wrap">
            <span class="field-icon">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                <rect x="2" y="4" width="20" height="16" rx="2"/><path d="m22 7-8.97 5.7a1.94 1.94 0 0 1-2.06 0L2 7"/>
              </svg>
            </span>
            <input
              type="email"
              id="email"
              name="email"
              class="field-input"
              placeholder="admin@callmyprof.com"
              required
              autocomplete="email"
              autofocus
            >
          </div>
        </div>

        <div class="field-group">
          <label class="field-label" for="password">${t(locale, "login.password")}</label>
          <div class="field-input-wrap">
            <span class="field-icon">
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                <rect width="18" height="11" x="3" y="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/>
              </svg>
            </span>
            <input
              type="password"
              id="password"
              name="password"
              class="field-input"
              placeholder="${t(locale, "login.password")}"
              required
              autocomplete="current-password"
            >
          </div>
        </div>

        <button type="submit" class="login-btn" id="loginBtn">
          <span class="btn-spinner"></span>
          <span class="btn-text">${t(locale, "login.submit")}</span>
          <span class="btn-loading-text">${t(locale, "common.loading")}</span>
          <span class="btn-arrow">&#8594;</span>
        </button>
      </form>

      <div class="login-footer">
        <p>CallMyProf &copy; ${(/* @__PURE__ */ new Date()).getFullYear()}</p>
      </div>
    </div>
  </div>

  <script>
    // Loading state on submit
    document.getElementById('loginForm').addEventListener('submit', function() {
      var btn = document.getElementById('loginBtn');
      btn.classList.add('loading');
    });

    // Focus animation on inputs
    document.querySelectorAll('.field-input').forEach(function(input) {
      input.addEventListener('focus', function() {
        this.closest('.field-group').classList.add('focused');
      });
      input.addEventListener('blur', function() {
        this.closest('.field-group').classList.remove('focused');
      });
    });
  <\/script>
</body>
</html>`;
}
__name(renderLoginPage, "renderLoginPage");
async function handleLogin(request, env) {
  const form = await parseFormData(request);
  const email = (form.email || "").trim().toLowerCase();
  const password = form.password || "";
  if (!email || !password) {
    return htmlResponse(renderLoginPage("Veuillez renseigner votre email et votre mot de passe."));
  }
  const user = await env.DB.prepare(
    "SELECT id, email, password_hash, role, nom, prenom FROM users WHERE email = ?"
  ).bind(email).first();
  if (!user) {
    return htmlResponse(renderLoginPage("Identifiants incorrects. V\xE9rifiez votre email et mot de passe."));
  }
  const valid = await verifyPassword(password, user.password_hash);
  if (!valid) {
    return htmlResponse(renderLoginPage("Identifiants incorrects. V\xE9rifiez votre email et mot de passe."));
  }
  const { cookie } = await createSession(env.DB, user.id);
  if (user.role === "eleve") {
    return redirectResponse("/portal", cookie);
  }
  if (user.role === "formateur") {
    return redirectResponse("/tutor", cookie);
  }
  return redirectResponse("/dashboard", cookie);
}
__name(handleLogin, "handleLogin");

