async function fetchDashboardData(db) {
  const now = /* @__PURE__ */ new Date();
  const monthStart = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-01`;
  const nextMonth = now.getMonth() === 11 ? `${now.getFullYear() + 1}-01-01` : `${now.getFullYear()}-${String(now.getMonth() + 2).padStart(2, "0")}-01`;
  const results = await db.batch([
    // 0: Total formateurs
    db.prepare("SELECT COUNT(*) as c FROM formateurs"),
    // 1: Formateurs valides
    db.prepare("SELECT COUNT(*) as c FROM formateurs WHERE application_status = 'valide'"),
    // 2: Formateurs en attente
    db.prepare("SELECT COUNT(*) as c FROM formateurs WHERE application_status IN ('submitted', 'en_attente')"),
    // 3: Total familles (parents)
    db.prepare("SELECT COUNT(*) as c FROM parents"),
    // 4: Total eleves
    db.prepare("SELECT COUNT(*) as c FROM eleves"),
    // 5: Cours du mois
    db.prepare("SELECT COUNT(*) as c FROM cours WHERE date_cours >= ? AND date_cours < ?").bind(monthStart, nextMonth),
    // 6: Leads pipeline stats
    db.prepare(`
      SELECT
        COUNT(*) as total,
        SUM(CASE WHEN statut = 'new' THEN 1 ELSE 0 END) as cnt_new,
        SUM(CASE WHEN statut = 'contacted' THEN 1 ELSE 0 END) as cnt_contacted,
        SUM(CASE WHEN statut = 'qualified' THEN 1 ELSE 0 END) as cnt_qualified,
        SUM(CASE WHEN statut = 'converted' THEN 1 ELSE 0 END) as cnt_converted
      FROM leads
    `),
    // 7: Overdue callbacks
    db.prepare("SELECT COUNT(*) as c FROM leads WHERE callback_date < datetime('now') AND statut NOT IN ('converted', 'lost')"),
    // 8: Derniers 5 cours
    db.prepare(`
      SELECT c.id, c.titre, c.date_cours, c.heure_debut, c.duree_minutes, c.type_cours, c.statut,
             f.nom as formateur_nom, f.prenom as formateur_prenom
      FROM cours c
      LEFT JOIN formateurs f ON f.id = c.formateur_id
      ORDER BY c.date_cours DESC, c.heure_debut DESC
      LIMIT 5
    `),
    // 9: Derniers 3 avis
    db.prepare(`
      SELECT a.id, a.note, a.commentaire, a.created_at,
             e.prenom as eleve_prenom,
             f.prenom as formateur_prenom, f.nom as formateur_nom
      FROM avis a
      LEFT JOIN eleves e ON e.id = a.eleve_id
      LEFT JOIN formateurs f ON f.id = a.formateur_id
      WHERE a.visible = 1
      ORDER BY a.created_at DESC
      LIMIT 3
    `),
    // 10: Recent 5 leads
    db.prepare(`
      SELECT id, prenom, nom, email, statut, service_type, created_at
      FROM leads ORDER BY created_at DESC LIMIT 5
    `)
  ]);
  const leadStats = results[6].results[0];
  return {
    totalFormateurs: results[0].results[0]?.c ?? 0,
    formateursValides: results[1].results[0]?.c ?? 0,
    formateursEnAttente: results[2].results[0]?.c ?? 0,
    totalFamilles: results[3].results[0]?.c ?? 0,
    totalEleves: results[4].results[0]?.c ?? 0,
    coursDuMois: results[5].results[0]?.c ?? 0,
    leadsTotal: leadStats?.total ?? 0,
    leadsNew: leadStats?.cnt_new ?? 0,
    leadsContacted: leadStats?.cnt_contacted ?? 0,
    leadsQualified: leadStats?.cnt_qualified ?? 0,
    leadsConverted: leadStats?.cnt_converted ?? 0,
    overdueCallbacks: results[7].results[0]?.c ?? 0,
    derniersCours: results[8].results ?? [],
    derniersAvis: results[9].results ?? [],
    recentLeads: results[10].results ?? []
  };
}
