async function serveFormateurDocument(env, id, docKey) {
  const validKeys = ["doc_identite_url", "doc_diplomes_url", "doc_siret_url", "doc_urssaf_url", "doc_casier_url", "doc_rib_url", "doc_cv_url", "photo_url", "signature_url"];
  if (!validKeys.includes(docKey)) {
    return errorResponse("Type de document invalide", 400);
  }
  const row = await env.DB.prepare(`SELECT ${docKey} FROM formateurs WHERE id = ?`).bind(id).first();
  if (!row || !row[docKey]) {
    return errorResponse("Document non trouve", 404);
  }
  const r2Key = row[docKey];
  const obj = await env.R2.get(r2Key);
  if (!obj) {
    return errorResponse("Fichier non trouve dans le stockage", 404);
  }
  const headers = new Headers();
  headers.set("Content-Type", obj.httpMetadata?.contentType || "application/octet-stream");
  if (obj.customMetadata?.originalName) {
    headers.set("Content-Disposition", `inline; filename="${obj.customMetadata.originalName}"`);
  }
  headers.set("Cache-Control", "private, max-age=3600");
  return new Response(obj.body, { headers });
}
