async function updateFormateur(env, id, request) {
  const body = await request.json();
  const existing = await env.DB.prepare("SELECT id FROM formateurs WHERE id = ?").bind(id).first();
  if (!existing) {
    return errorResponse("Formateur non trouve", 404);
  }
  const allowedFields = [
    "nom",
    "prenom",
    "email",
    "telephone",
    "ville",
    "code_postal",
    "rayon_km",
    "bio",
    "diplomes",
    "experience_annees",
    "tarif_horaire_individuel",
    "tarif_horaire_collectif",
    "accepte_domicile",
    "accepte_collectif",
    "accepte_visio",
    "lieu_collectif",
    "admin_notes"
  ];
  const updates = ["updated_at = datetime('now')"];
  const params = [];
  for (const field of allowedFields) {
    if (body[field] !== void 0) {
      updates.push(`${field} = ?`);
      params.push(body[field]);
    }
  }
  if (updates.length <= 1) {
    return errorResponse("Aucun champ a mettre a jour");
  }
  params.push(id);
  await env.DB.prepare(
    `UPDATE formateurs SET ${updates.join(", ")} WHERE id = ?`
  ).bind(...params).run();
  return jsonResponse({ success: true });
}
