function thematiqueBadges(thematiquesStr) {
  if (!thematiquesStr) return '<span style="color:var(--gray-400);font-size:12px">Aucune</span>';
  const list = thematiquesStr.split(",").map((t2) => t2.trim()).filter(Boolean);
  const shown = list.slice(0, 3);
  const rest = list.length - 3;
  let html = '<div class="thematique-badges">';
  for (const t2 of shown) {
    html += `<span class="thematique-badge" title="${escapeHtml(t2)}">${escapeHtml(truncate(t2, 15))}</span>`;
  }
  if (rest > 0) {
    html += `<span class="thematique-more" title="${escapeHtml(list.slice(3).join(", "))}">+${rest}</span>`;
  }
  html += "</div>";
  return html;
}
