async function toggleActif(env, type, id) {
  try {
    let table;
    switch (type) {
      case "domaine":
      case "domaines":
        table = "domaines";
        break;
      case "sous-domaine":
      case "sous-domaines":
        table = "sous_domaines";
        break;
      case "thematique":
      case "thematiques":
        table = "thematiques";
        break;
      default:
        return errorResponse("Type invalide. Valeurs acceptees: domaine, sous-domaine, thematique");
    }
    const current = await env.DB.prepare(`SELECT id, actif FROM ${table} WHERE id = ?`).bind(id).first();
    if (!current) {
      return errorResponse(`${type} non trouve(e)`, 404);
    }
    const newActif = current.actif === 1 ? 0 : 1;
    await env.DB.prepare(`UPDATE ${table} SET actif = ? WHERE id = ?`).bind(newActif, id).run();
    return jsonResponse({ success: true, actif: newActif });
  } catch (error) {
    console.error("Error toggling actif:", error);
    return errorResponse("Erreur lors du changement de statut", 500);
  }
}
