function calculateCreditImpot(montant, eligible) {
  const credit = eligible ? Math.round(montant * 0.5 * 100) / 100 : 0;
  return {
    brut: Math.round(montant * 100) / 100,
    credit,
    resteACharge: Math.round((montant - credit) * 100) / 100
  };
}
__name(calculateCreditImpot, "calculateCreditImpot");
function formatPrix(montant) {
  return montant.toLocaleString("fr-FR", {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  }) + " \u20AC";
}
__name(formatPrix, "formatPrix");
function formatTarifHoraire(montant) {
  return formatPrix(montant).replace(" \u20AC", " \u20AC/h");
}
__name(formatTarifHoraire, "formatTarifHoraire");
function labelTypeCours(type) {
  switch (type) {
    case "individuel":
      return "Individuel";
    case "collectif":
      return "Collectif";
    case "mixte":
      return "Mixte";
    default:
      return type;
  }
}
