async function updatePackageType(env, id, request) {
  let body;
  try {
    body = await request.json();
  } catch {
    return errorResponse("Corps de requete JSON invalide");
  }
  const existing = await env.DB.prepare("SELECT id FROM package_types WHERE id = ?").bind(id).first();
  if (!existing) {
    return errorResponse("Type de package non trouve", 404);
  }
  const allowedFields = [
    "nom",
    "type_cours",
    "nb_heures",
    "prix",
    "prix_par_heure",
    "eligible_credit_impot",
    "duree_validite_jours",
    "max_eleves_collectif",
    "actif",
    "ordre"
  ];
  const updates = [];
  const params = [];
  for (const field of allowedFields) {
    if (body[field] !== void 0) {
      updates.push(`${field} = ?`);
      params.push(body[field]);
    }
  }
  if (updates.length === 0) {
    return errorResponse("Aucun champ a mettre a jour");
  }
  params.push(id);
  await env.DB.prepare(
    `UPDATE package_types SET ${updates.join(", ")} WHERE id = ?`
  ).bind(...params).run();
  return jsonResponse({ success: true });
}
