var RESEND_API_URL = "https://api.resend.com/emails";
function getFromEmail(locale) {
  if (locale === "fr") {
    return "CallMyProf <nepasrepondre@callmyprof.com>";
  }
  return "CallMyProf <noreply@callmyprof.com>";
}
__name(getFromEmail, "getFromEmail");
async function sendEmail(env, options) {
  if (!env.RESEND_API_KEY) {
    console.error("RESEND_API_KEY not configured");
    return { success: false, error: "Email service not configured" };
  }
  try {
    const response = await fetch(RESEND_API_URL, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${env.RESEND_API_KEY}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        from: getFromEmail(options.locale),
        to: [options.to],
        subject: options.subject,
        html: options.html,
        reply_to: options.replyTo || "contact@callmyprof.com"
      })
    });
    const data = await response.json();
    if (!response.ok) {
      console.error("Resend API error:", data);
      return { success: false, error: data.message || "Failed to send email" };
    }
    return { success: true, id: data.id };
  } catch (error) {
    console.error("Email send error:", error);
    return { success: false, error: "Network error sending email" };
  }
}
__name(sendEmail, "sendEmail");
