async function updateLeadStatus(env, leadId, request) {
  const data = await request.json();
  const updates = [];
  const values = [];
  if (data.statut) {
    const validStatuts = ["new", "contacted", "qualified", "converted", "lost"];
    if (!validStatuts.includes(data.statut)) {
      return errorResponse("Invalid status.");
    }
    updates.push("statut = ?");
    values.push(data.statut);
  }
  if (data.callback_date !== void 0) {
    updates.push("callback_date = ?");
    values.push(data.callback_date || null);
  }
  if (data.callback_notes !== void 0) {
    updates.push("callback_notes = ?");
    values.push(data.callback_notes || null);
  }
  if (updates.length === 0) {
    return errorResponse("No updates provided.");
  }
  updates.push("updated_at = datetime('now')");
  values.push(leadId);
  try {
    await env.DB.prepare(
      `UPDATE leads SET ${updates.join(", ")} WHERE id = ?`
    ).bind(...values).run();
    // Auto-send portal signup invite when lead is converted
    if (data.statut === "converted") {
      try {
        const lead = await env.DB.prepare("SELECT id, nom, prenom, email FROM leads WHERE id = ?").bind(leadId).first();
        if (lead && lead.email) {
          const existing = await env.DB.prepare("SELECT id FROM users WHERE email = ? AND role = 'eleve'").bind(lead.email).first();
          if (!existing) {
            await sendSignupInvite(env, lead.email, (lead.prenom || "") + " " + (lead.nom || ""), "student", lead.id);
          }
        }
      } catch (e) { console.error("Failed to send student signup invite:", e); }
    }
    return jsonResponse({ success: true });
  } catch (error) {
    console.error("Error updating lead:", error);
    return errorResponse("Failed to update lead.", 500);
  }
}
