      activePage: "leads",
      content: `
        <a href="/leads" class="back-link">&#8592; Back to Leads</a>
        <div class="empty-state">
          <span class="empty-icon">&#128533;</span>
          <div class="empty-title">Lead not found</div>
          <div class="empty-text">This lead may have been deleted.</div>
        </div>`,
