// src/api/payment-gateways/checkout.ts
var CheckoutAdapter = class {
  static {
    __name(this, "CheckoutAdapter");
  }
  secretKey;
  baseUrl = "https://api.sandbox.checkout.com";
  constructor(secretKey) {
    this.secretKey = secretKey;
  }
  async createCheckout(params) {
    const response = await fetch(`${this.baseUrl}/hosted-payments`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${this.secretKey}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        amount: params.amount,
        currency: params.currency.toUpperCase(),
        reference: params.referenceId,
        description: params.description,
        customer: {
          email: params.customerEmail,
          name: params.customerName
        },
        billing: {
          address: {
            country: "LB"
          }
        },
        success_url: params.successUrl,
        cancel_url: params.cancelUrl,
        failure_url: params.cancelUrl,
        metadata: {
          reference_id: params.referenceId
        }
      })
    });
    if (!response.ok) {
      const errorBody = await response.text();
      console.error("Checkout.com create session error:", response.status, errorBody);
      throw new Error(`Checkout.com error: ${response.status}`);
    }
    const data = await response.json();
    return {
      sessionId: data.id,
      redirectUrl: data._links.redirect.href
    };
  }
  async verifyWebhook(request, secret) {
    const body = await request.text();
    const signature = request.headers.get("cko-signature") || "";
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      "raw",
      encoder.encode(secret),
      { name: "HMAC", hash: "SHA-256" },
      false,
      ["sign"]
    );
    const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(body));
    const expectedSig = Array.from(new Uint8Array(sig)).map((b) => b.toString(16).padStart(2, "0")).join("");
    if (signature !== expectedSig) {
      console.warn("Checkout.com webhook signature mismatch");
    }
    const event = JSON.parse(body);
    const referenceId = event.data?.metadata?.reference_id || event.data?.reference || "";
    const transactionId = event.data?.action_id || event.data?.id || "";
    const isPaid = event.type === "payment_approved" || event.type === "payment_captured";
    return {
      referenceId,
      transactionId,
      sessionId: event.data.id,
      gateway: "checkout",
      status: isPaid ? "paid" : "failed",
      rawData: event
    };
  }
};

// src/api/payment-gateways/paypal.ts
var PayPalAdapter = class {
  static {
    __name(this, "PayPalAdapter");
  }
  clientId;
  secret;
  baseUrl;
  constructor(clientId, secret, sandbox = true) {
    this.clientId = clientId;
    this.secret = secret;
    this.baseUrl = sandbox ? "https://api-m.sandbox.paypal.com" : "https://api-m.paypal.com";
  }
  async getAccessToken() {
    const credentials = btoa(`${this.clientId}:${this.secret}`);
    const response = await fetch(`${this.baseUrl}/v1/oauth2/token`, {
      method: "POST",
      headers: {
        "Authorization": `Basic ${credentials}`,
        "Content-Type": "application/x-www-form-urlencoded"
      },
      body: "grant_type=client_credentials"
    });
    if (!response.ok) {
      throw new Error(`PayPal auth failed: ${response.status}`);
    }
    const data = await response.json();
    return data.access_token;
  }
  async createCheckout(params) {
    const accessToken = await this.getAccessToken();
    const amountStr = (params.amount / 100).toFixed(2);
    const response = await fetch(`${this.baseUrl}/v2/checkout/orders`, {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${accessToken}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        intent: "CAPTURE",
        purchase_units: [{
          reference_id: params.referenceId,
          custom_id: params.referenceId,
          description: params.description,
          amount: {
            currency_code: params.currency.toUpperCase(),
            value: amountStr
          }
        }],
        payment_source: {
          paypal: {
            experience_context: {
              payment_method_preference: "IMMEDIATE_PAYMENT_REQUIRED",
              brand_name: "CallMyProf",
              locale: "fr-FR",
              landing_page: "LOGIN",
              user_action: "PAY_NOW",
              return_url: params.successUrl,
              cancel_url: params.cancelUrl
            }
          }
        }
      })
    });
    if (!response.ok) {
      const errorBody = await response.text();
      console.error("PayPal create order error:", response.status, errorBody);
      throw new Error(`PayPal error: ${response.status}`);
    }
    const data = await response.json();
    const approveLink = data.links.find((l) => l.rel === "payer-action") || data.links.find((l) => l.rel === "approve");
    if (!approveLink) {
      throw new Error("PayPal: no approval URL in response");
    }
    return {
      sessionId: data.id,
      redirectUrl: approveLink.href
    };
  }
  async verifyWebhook(request, _secret) {
    const body = await request.text();
    const event = JSON.parse(body);
    const purchaseUnit = event.resource?.purchase_units?.[0];
    const referenceId = purchaseUnit?.custom_id || purchaseUnit?.reference_id || "";
    const captureId = purchaseUnit?.payments?.captures?.[0]?.id || event.resource.id;
    const isPaid = event.event_type === "PAYMENT.CAPTURE.COMPLETED" || event.event_type === "CHECKOUT.ORDER.APPROVED";
    return {
      referenceId,
      transactionId: captureId,
      sessionId: event.resource.id,
      gateway: "paypal",
      status: isPaid ? "paid" : "failed",
      rawData: event
    };
  }
};

// src/api/payment-gateways/index.ts
function getPaymentAdapter(gateway, env) {
  switch (gateway) {
    case "checkout": {
      if (!env.CHECKOUT_SECRET_KEY) throw new Error("CHECKOUT_SECRET_KEY not configured");
      return new CheckoutAdapter(env.CHECKOUT_SECRET_KEY);
    }
    case "paypal": {
      if (!env.PAYPAL_CLIENT_ID || !env.PAYPAL_SECRET) throw new Error("PayPal credentials not configured");
      const sandbox = env.PAYPAL_SANDBOX !== "false";
      return new PayPalAdapter(env.PAYPAL_CLIENT_ID, env.PAYPAL_SECRET, sandbox);
    }
    default:
      throw new Error(`Unknown payment gateway: ${gateway}`);
  }
}
__name(getPaymentAdapter, "getPaymentAdapter");

// src/api/chatbot.ts
var SYSTEM_PROMPT = `You are CallMyProf's friendly assistant. CallMyProf is an international tutoring platform that connects students with qualified tutors.

Key information:
- Pricing starts from $15/hour for individual sessions, $8/hour for group classes, $12/hour for online sessions
- Tutors are based in Lebanon and are carefully vetted with background checks
- All tutors sign non-compete agreements to ensure professional service
- We offer tutoring in Mathematics, Sciences, Languages, Business, Technology, Arts, Test Prep, and more
- Students/parents fill out a form and we call them back within 24 hours
- We offer individual (1-on-1), group (up to 6 students), and online sessions
- Payment methods: Stripe, PayPal, cash, bank transfer

How to respond:
- Be concise, friendly, and helpful
- If a question is about pricing, give the starting rates
- If a question is about subjects, list the main categories
- If a question is about how it works, explain: 1) Fill the form 2) We call you 3) We match you with a tutor 4) Start learning
- If a question is complex or about specific scheduling, suggest they fill the contact form or call
- Respond in the same language the user writes in (English, French, or Arabic)
- Keep responses under 150 words
- Don't make up information you don't have`;
async function handleChat(env, request) {
  try {
    const data = await request.json();
    if (!data.message?.trim()) {
      return errorResponse("Message is required.");
    }
    const messages = [
      { role: "system", content: SYSTEM_PROMPT }
    ];
    if (data.history && Array.isArray(data.history)) {
      const recent = data.history.slice(-6);
      for (const msg of recent) {
        if (msg.role === "user" || msg.role === "assistant") {
          messages.push({ role: msg.role, content: msg.content });
        }
      }
    }
    messages.push({ role: "user", content: data.message.trim() });
    const response = await env.AI.run("@cf/meta/llama-3.1-8b-instruct-fp8", {
      messages,
      max_tokens: 300,
      temperature: 0.7
    });
    return jsonResponse({
      success: true,
      reply: response.response || "I'm sorry, I couldn't process your question. Please try again or fill out our contact form for personalized help!"
    });
  } catch (error) {
    console.error("Chatbot error:", error);
    return jsonResponse({
      success: true,
      reply: "I'm having trouble right now. Please fill out the contact form above and our team will get back to you within 24 hours!"
    });
  }
}
__name(handleChat, "handleChat");

