async function handleSignup(request, env, portalType) {
  try {
    const form = await parseFormData(request);
    const token = form.token || new URL(request.url).searchParams.get("token") || "";
    const password = form.password || "";
    const passwordConfirm = form.password_confirm || "";
    if (!token) {
      return htmlResponse(renderSignupPage("Invalid or missing signup token.", null, portalType, ""));
    }
    if (password.length < 8) {
      return htmlResponse(renderSignupPage("Password must be at least 8 characters.", null, portalType, token));
    }
    if (password !== passwordConfirm) {
      return htmlResponse(renderSignupPage("Passwords do not match.", null, portalType, token));
    }
    const tokenRow = await env.DB.prepare(
      "SELECT * FROM signup_tokens WHERE token = ? AND used = 0 AND expires_at > datetime('now')"
    ).bind(token).first();
    if (!tokenRow) {
      return htmlResponse(renderSignupPage("This signup link is invalid or has expired. Please contact support.", null, portalType, ""));
    }
    const existingUser = await env.DB.prepare("SELECT id FROM users WHERE email = ?").bind(tokenRow.email).first();
    if (existingUser) {
      await env.DB.prepare("UPDATE signup_tokens SET used = 1 WHERE id = ?").bind(tokenRow.id).run();
      return htmlResponse(renderPortalLoginPage("An account with this email already exists. Please log in.", null, portalType));
    }
    const passwordHash = await hashPassword(password);
    const userId = generateId();
    if (tokenRow.role === "student" && tokenRow.lead_id) {
      const lead = await env.DB.prepare("SELECT nom, prenom, telephone FROM leads WHERE id = ?").bind(tokenRow.lead_id).first();
      await env.DB.prepare(
        "INSERT INTO users (id, email, password_hash, role, lead_id, nom, prenom, telephone, created_at, updated_at) VALUES (?, ?, ?, 'eleve', ?, ?, ?, ?, datetime('now'), datetime('now'))"
      ).bind(userId, tokenRow.email, passwordHash, tokenRow.lead_id, lead ? lead.nom || "" : "", lead ? lead.prenom || "" : "", lead ? lead.telephone || "" : "").run();
    } else if (tokenRow.role === "formateur" && tokenRow.formateur_id) {
      const fmt = await env.DB.prepare("SELECT nom, prenom, telephone FROM formateurs WHERE id = ?").bind(tokenRow.formateur_id).first();
      await env.DB.prepare(
        "INSERT INTO users (id, email, password_hash, role, formateur_id, nom, prenom, telephone, created_at, updated_at) VALUES (?, ?, ?, 'formateur', ?, ?, ?, ?, datetime('now'), datetime('now'))"
      ).bind(userId, tokenRow.email, passwordHash, tokenRow.formateur_id, fmt ? fmt.nom || "" : "", fmt ? fmt.prenom || "" : "", fmt ? fmt.telephone || "" : "").run();
    }
    await env.DB.prepare("UPDATE signup_tokens SET used = 1 WHERE id = ?").bind(tokenRow.id).run();
    const { cookie } = await createSession(env.DB, userId);
    return redirectResponse(tokenRow.role === "formateur" ? "/tutor" : "/portal", cookie);
  } catch (error) {
    console.error("Signup error:", error);
    return htmlResponse(renderSignupPage("An error occurred: " + (error instanceof Error ? error.message : String(error)), null, portalType, ""));
  }
}
__name(handleSignup, "handleSignup");

