async function handleResetPassword(request, env, portalType) {
  const form = await parseFormData(request);
  const token = form.token || "";
  const password = form.password || "";
  const passwordConfirm = form.password_confirm || "";
  if (!token) return htmlResponse(renderResetPasswordPage("Invalid reset link.", token, portalType));
  if (password.length < 8) return htmlResponse(renderResetPasswordPage("Password must be at least 8 characters.", token, portalType));
  if (password !== passwordConfirm) return htmlResponse(renderResetPasswordPage("Passwords do not match.", token, portalType));
  const tokenRow = await env.DB.prepare(
    "SELECT * FROM password_reset_tokens WHERE token = ? AND used = 0 AND expires_at > datetime('now')"
  ).bind(token).first();
  if (!tokenRow) return htmlResponse(renderResetPasswordPage("This reset link is invalid or has expired.", token, portalType));
  const passwordHash = await hashPassword(password);
  await env.DB.prepare("UPDATE users SET password_hash = ?, updated_at = datetime('now') WHERE id = ?").bind(passwordHash, tokenRow.user_id).run();
  await env.DB.prepare("UPDATE password_reset_tokens SET used = 1 WHERE id = ?").bind(tokenRow.id).run();
  return htmlResponse(renderPortalLoginPage("Password updated successfully! Please log in.", null, portalType));
}
__name(handleResetPassword, "handleResetPassword");

