async function renderTutorDashboard(env, user) {
  const fmtId = user.formateur_id;
  const now = new Date().toISOString().split("T")[0];
  let upcomingCount = 0, totalTaught = 0, totalEarned = 0, pendingEarnings = 0;
  let nextClass = null;
  if (fmtId) {
    const uc = await env.DB.prepare("SELECT COUNT(*) as c FROM cours WHERE formateur_id = ? AND date_cours >= ? AND statut != 'annule'").bind(fmtId, now).first();
    upcomingCount = uc?.c || 0;
    const tt = await env.DB.prepare("SELECT COUNT(*) as c FROM cours WHERE formateur_id = ? AND statut = 'termine'").bind(fmtId).first();
    totalTaught = tt?.c || 0;
    const te = await env.DB.prepare("SELECT SUM(montant) as s FROM paiements_formateurs WHERE formateur_id = ? AND statut = 'paye'").bind(fmtId).first();
    totalEarned = te?.s || 0;
    const pe = await env.DB.prepare("SELECT SUM(montant) as s FROM paiements_formateurs WHERE formateur_id = ? AND statut = 'en_attente'").bind(fmtId).first();
    pendingEarnings = pe?.s || 0;
    nextClass = await env.DB.prepare(
      "SELECT c.id, c.date_cours, c.heure_debut, c.duree_minutes, t.nom as thematique FROM cours c LEFT JOIN thematiques t ON t.id = c.thematique_id WHERE c.formateur_id = ? AND c.date_cours >= ? AND c.statut != 'annule' ORDER BY c.date_cours ASC, c.heure_debut ASC LIMIT 1"
    ).bind(fmtId, now).first();
  }
  let nextClassHtml = '';
  if (nextClass) {
    nextClassHtml = `<div class="p-card" style="margin-bottom:24px;border-left:4px solid #DC2626">
      <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px">
        <div>
          <div style="font-size:13px;color:#DC2626;font-weight:600;text-transform:uppercase;letter-spacing:0.5px">Next Class</div>
          <div style="font-size:18px;font-weight:700;color:#0F172A;margin-top:4px">${nextClass.date_cours} at ${nextClass.heure_debut}</div>
          <div style="font-size:13px;color:#64748B">${escapeHtml(nextClass.thematique || "Class")} &bull; ${nextClass.duree_minutes || 60} min</div>
        </div>
      </div>
    </div>`;
  }
  const content = `
    <div class="p-welcome-banner">
      <h2>Welcome back, ${escapeHtml((user.prenom || "") + " " + (user.nom || "")).trim() || "Tutor"}!</h2>
      <p>Here's an overview of your teaching activity.</p>
    </div>
    ${nextClassHtml}
    <div class="p-stats-grid">
      <div class="p-stat-card"><div class="p-stat-value" style="color:#3B82F6">${upcomingCount}</div><div class="p-stat-label">Upcoming Classes</div></div>
      <div class="p-stat-card"><div class="p-stat-value" style="color:#22C55E">${totalTaught}</div><div class="p-stat-label">Classes Taught</div></div>
      <div class="p-stat-card"><div class="p-stat-value" style="color:#0F172A">$${(totalEarned || 0).toFixed(2)}</div><div class="p-stat-label">Total Earned</div></div>
      <div class="p-stat-card"><div class="p-stat-value" style="color:#F59E0B">$${(pendingEarnings || 0).toFixed(2)}</div><div class="p-stat-label">Pending</div></div>
    </div>
  `;
  return htmlTutorPage({ title: "Dashboard", pageTitle: "Dashboard", activePage: "dashboard", content, userName: `${user.prenom} ${user.nom}` });
}
__name(renderTutorDashboard, "renderTutorDashboard");

async function renderTutorClasses(env, user) {
  const fmtId = user.formateur_id;
  const now = new Date().toISOString().split("T")[0];
  let upcoming = [], past = [];
  if (fmtId) {
    const ures = await env.DB.prepare("SELECT c.*, t.nom as thematique FROM cours c LEFT JOIN thematiques t ON t.id = c.thematique_id WHERE c.formateur_id = ? AND c.date_cours >= ? AND c.statut != 'annule' ORDER BY c.date_cours ASC, c.heure_debut ASC").bind(fmtId, now).all();
    upcoming = ures.results || [];
    const pres = await env.DB.prepare("SELECT c.*, t.nom as thematique FROM cours c LEFT JOIN thematiques t ON t.id = c.thematique_id WHERE c.formateur_id = ? AND (c.date_cours < ? OR c.statut = 'annule') ORDER BY c.date_cours DESC LIMIT 50").bind(fmtId, now).all();
    // Note: c.* now includes tutor_status from migration 0013
    // Note: c.* includes video_provider, video_room_url, video_host_url from cours table
    past = pres.results || [];
  }
  const allClasses = [...upcoming, ...past];
  const classDates = {};
  allClasses.forEach(c => {
    if (!classDates[c.date_cours]) classDates[c.date_cours] = [];
    classDates[c.date_cours].push({ heure_debut: c.heure_debut, thematique: c.thematique, statut: c.statut });
  });
  const classDatesJson = JSON.stringify(classDates).replace(/<\/script>/gi, "<\\/script>");
  const tutorAcceptBadge = (status) => {
    if (status === 'accepted') return '<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;font-weight:600;background:#DCFCE7;color:#166534">Accepted</span>';
    if (status === 'rejected') return '<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;font-weight:600;background:#FEE2E2;color:#991B1B">Rejected</span>';
    if (status === 'modification_requested') return '<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;font-weight:600;background:#FEF3C7;color:#92400E">Modified</span>';
    return '<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;font-weight:600;background:#FEF9C3;color:#854D0E">Pending</span>';
  };
  const tableRow = (c) => {
    const sb = c.statut === "termine" ? '<span class="p-badge p-badge-green">Completed</span>'
      : c.statut === "annule" ? '<span class="p-badge p-badge-gray">Cancelled</span>'
      : '<span class="p-badge p-badge-blue">Scheduled</span>';
    const typeLabel = c.type_cours === "groupe" ? "👥 Group" : c.type_cours === "en_ligne" ? "🌐 Online" : "👤 Individual";
    const duration = c.duree_minutes ? c.duree_minutes + " min" : "—";
    const maxStudents = c.max_eleves || "—";
    const lieu = c.lieu ? escapeHtml(c.lieu) : '<span style="color:#94A3B8">—</span>';
    const titre = c.titre ? escapeHtml(c.titre) : '<span style="color:#94A3B8">—</span>';
    const isUpcoming = c.date_cours >= now;
    const videoUrl = c.video_host_url || c.video_room_url;
    const joinBtn = isUpcoming && videoUrl && c.statut !== 'annule' ? `<a href="/session/${c.id}?role=host" class="p-btn p-btn-primary" style="padding:4px 14px;font-size:12px" target="_blank">Join &rarr;</a>` : '<span style="color:#94A3B8">\u2014</span>';
    const acceptCol = tutorAcceptBadge(c.tutor_status || 'pending');
    const detailBtn = isUpcoming && (c.tutor_status || 'pending') === 'pending' ? `<a href="/tutor/classes/${c.id}" class="p-btn" style="padding:4px 14px;font-size:12px;background:#F59E0B;color:#fff;border-radius:6px;text-decoration:none">Respond</a>` : `<a href="/tutor/classes/${c.id}" style="font-size:12px;color:#2563EB;text-decoration:underline">Details</a>`;
    return `<tr class="srow">
      <td style="padding:10px 14px;white-space:nowrap">${c.date_cours}</td>
      <td style="padding:10px 14px">${c.heure_debut}</td>
      <td style="padding:10px 14px">${escapeHtml(c.thematique || "—")}</td>
      <td style="padding:10px 14px">${titre}</td>
      <td style="padding:10px 14px">${typeLabel}</td>
      <td style="padding:10px 14px">${duration}</td>
      <td style="padding:10px 14px">${maxStudents}</td>
      <td style="padding:10px 14px">${lieu}</td>
      <td style="padding:10px 14px">${sb}</td>
      <td style="padding:10px 14px">${acceptCol}</td>
      <td style="padding:10px 14px">${detailBtn} ${joinBtn !== '<span style="color:#94A3B8">\u2014</span>' ? joinBtn : ''}</td>
    </tr>`;
  };
  const tableHead = `<thead><tr style="background:#F8FAFC;border-bottom:2px solid #E2E8F0">
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B;white-space:nowrap">Date</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Time</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Subject</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Title</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Type</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Duration</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Max Students</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Location</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Status</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Acceptance</th>
    <th style="padding:10px 14px;text-align:left;font-weight:600;color:#64748B">Action</th>
  </tr></thead>`;
  const upRows = upcoming.length > 0 ? upcoming.map(tableRow).join("") : `<tr><td colspan="11" style="text-align:center;padding:32px;color:#94A3B8">No upcoming classes</td></tr>`;
  const pastRows = past.length > 0 ? past.map(tableRow).join("") : `<tr><td colspan="11" style="text-align:center;padding:32px;color:#94A3B8">No past classes yet</td></tr>`;
  const makeTable = (rows) => `<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px">${tableHead}<tbody>${rows}</tbody></table></div>`;
  const content = `
    <style>
      .cal-wrap{background:#fff;border-radius:12px;border:1px solid #E2E8F0;padding:20px;margin-bottom:24px}
      .cal-hdr{display:flex;align-items:center;justify-content:space-between;margin-bottom:16px}
      .cal-nbtn{background:#F1F5F9;border:none;width:32px;height:32px;border-radius:8px;cursor:pointer;font-size:18px;color:#475569;display:flex;align-items:center;justify-content:center}
      .cal-nbtn:hover{background:#E2E8F0}
      .cal-title{font-weight:700;font-size:16px;color:#0F172A}
      .cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:3px}
      .cal-dn{text-align:center;font-size:11px;font-weight:600;color:#94A3B8;padding:6px 0}
      .cal-d{position:relative;text-align:center;padding:6px 2px;border-radius:8px;font-size:13px;min-height:34px}
      .cal-d.om{color:#CBD5E1}
      .cal-d.td{background:#FEF2F2;font-weight:700;color:#DC2626}
      .cal-d.hs{cursor:pointer}
      .cal-d.hs:hover{background:#EFF6FF}
      .cal-dot{width:5px;height:5px;border-radius:50%;margin:2px auto 0}
      .cal-pop{display:none;position:absolute;left:50%;transform:translateX(-50%);top:110%;z-index:200;background:#fff;border:1px solid #E2E8F0;border-radius:10px;padding:10px 12px;min-width:180px;box-shadow:0 8px 24px rgba(0,0,0,0.12);text-align:left;pointer-events:none}
      .cal-d.hs:hover .cal-pop{display:block}
      .srow{border-bottom:1px solid #F1F5F9}
      .srow:last-child{border-bottom:none}
      .srow:hover{background:#FAFBFF}
    </style>
    <div class="cal-wrap">
      <div class="cal-hdr">
        <button class="cal-nbtn" onclick="calNav(-1)">&#8249;</button>
        <div class="cal-title" id="calLbl"></div>
        <button class="cal-nbtn" onclick="calNav(1)">&#8250;</button>
      </div>
      <div class="cal-grid" id="calDN"></div>
      <div class="cal-grid" id="calG"></div>
      <div style="display:flex;gap:16px;margin-top:12px;font-size:12px;color:#64748B">
        <span style="display:flex;align-items:center;gap:5px"><span style="width:8px;height:8px;border-radius:50%;background:#2563EB;display:inline-block"></span>Upcoming</span>
        <span style="display:flex;align-items:center;gap:5px"><span style="width:8px;height:8px;border-radius:50%;background:#10B981;display:inline-block"></span>Completed</span>
        <span style="display:flex;align-items:center;gap:5px"><span style="width:8px;height:8px;border-radius:50%;background:#94A3B8;display:inline-block"></span>Cancelled</span>
      </div>
    </div>
    <div class="p-tabs">
      <div class="p-tab active" onclick="showTab('up',this)">Upcoming (${upcoming.length})</div>
      <div class="p-tab" onclick="showTab('ps',this)">Past (${past.length})</div>
    </div>
    <div id="tab-up" class="p-card" style="padding:0;overflow:hidden">${makeTable(upRows)}</div>
    <div id="tab-ps" class="p-card" style="display:none;padding:0;overflow:hidden">${makeTable(pastRows)}</div>
    <script>
    var SD=${classDatesJson},todayS='${now}',cY,cM;
    (function(){var d=new Date();cY=d.getFullYear();cM=d.getMonth()})();
    var DNs=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'],MNs=['January','February','March','April','May','June','July','August','September','October','November','December'];
    function renderCal(){
      document.getElementById('calLbl').textContent=MNs[cM]+' '+cY;
      document.getElementById('calDN').innerHTML=DNs.map(function(n){return'<div class="cal-dn">'+n+'<\/div>'}).join('');
      var fd=new Date(cY,cM,1).getDay(),dim=new Date(cY,cM+1,0).getDate(),dip=new Date(cY,cM,0).getDate(),cells='';
      for(var i=fd-1;i>=0;i--)cells+='<div class="cal-d om">'+(dip-i)+'<\/div>';
      for(var d=1;d<=dim;d++){
        var ds=cY+'-'+String(cM+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
        var ss=SD[ds]||[],isTd=ds===todayS,isUp=ds>=todayS;
        var dc=isUp?'#2563EB':'#94A3B8';
        if(!isUp&&ss.some(function(s){return s.statut==='termine'}))dc='#10B981';
        var pop='';
        if(ss.length){pop='<div class="cal-pop"><div style="font-weight:600;font-size:11px;color:#64748B;margin-bottom:4px">'+ds+'<\/div>';ss.forEach(function(s){var sc=s.statut==='termine'?'#10B981':s.statut==='annule'?'#94A3B8':'#2563EB';pop+='<div style="padding:3px 0;border-top:1px solid #F1F5F9;font-size:12px"><span style="color:'+sc+';font-weight:600">'+s.heure_debut+'<\/span> &bull; '+(s.thematique||'Class')+'<\/div>';});pop+='<\/div>';}
        cells+='<div class="cal-d'+(ss.length?' hs':'')+(isTd?' td':'')+'">' +d+(ss.length?'<div class="cal-dot" style="background:'+dc+'"><\/div>':'')+pop+'<\/div>';
      }
      var rem=7-((fd+dim)%7);if(rem<7)for(var d=1;d<=rem;d++)cells+='<div class="cal-d om">'+d+'<\/div>';
      document.getElementById('calG').innerHTML=cells;
    }
    function calNav(dir){cM+=dir;if(cM>11){cM=0;cY++;}if(cM<0){cM=11;cY--;}renderCal();}
    function showTab(n,el){document.getElementById('tab-up').style.display=n==='up'?'block':'none';document.getElementById('tab-ps').style.display=n==='ps'?'block':'none';document.querySelectorAll('.p-tab').forEach(function(t){t.classList.remove('active')});el.classList.add('active');}
    renderCal();
    <\/script>
  `;
  return htmlTutorPage({ title: "My Classes", pageTitle: "My Classes", activePage: "classes", content, userName: `${user.prenom} ${user.nom}` });
}
