    document.getElementById('addressForm').addEventListener('submit',async function(e){e.preventDefault();const d=Object.fromEntries(new FormData(this).entries());const r=await fetch('/api/tutor/profile',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(d)});const j=await r.json();if(j.success)location.href='/tutor/profile?saved=1';else alert(j.error||'Failed');});
