async function renderTutorSecurity(env, user) {
  const content = `
    <div class="p-card">
      <div class="p-card-title">Change Password</div>
      <form id="securityForm">
        <div class="p-form-group"><label class="p-form-label">Current Password</label><input class="p-form-input" type="password" name="current_password" required></div>
        <div class="p-form-group"><label class="p-form-label">New Password</label><input class="p-form-input" type="password" name="new_password" required minlength="8" placeholder="Minimum 8 characters"></div>
        <div class="p-form-group"><label class="p-form-label">Confirm New Password</label><input class="p-form-input" type="password" name="confirm_password" required minlength="8"></div>
        <button type="submit" class="p-btn p-btn-primary">Update Password</button>
      </form>
    </div>
    <div class="p-card" style="margin-top:16px">
      <div class="p-card-title">Account Info</div>
      <p style="color:#64748B;font-size:14px">Last login: ${user.last_login ? new Date(user.last_login).toLocaleString() : "N/A"}</p>
      <p style="color:#64748B;font-size:14px">Account created: ${user.created_at ? new Date(user.created_at).toLocaleDateString() : "N/A"}</p>
    </div>
    <script>
    document.getElementById('securityForm').addEventListener('submit', async function(e) {
      e.preventDefault();
      const fd = new FormData(this);
      const data = Object.fromEntries(fd.entries());
      if (data.new_password !== data.confirm_password) { alert('Passwords do not match'); return; }
      const res = await fetch('/api/tutor/password', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) });
      const json = await res.json();
      if (json.success) { location.href = '/tutor/security?changed=1'; } else { alert(json.error || 'Failed'); }
    });
    <\/script>
  `;
  return htmlTutorPage({ title: "Security", pageTitle: "Security", activePage: "security", content, userName: `${user.prenom} ${user.nom}` });
}
__name(renderTutorSecurity, "renderTutorSecurity");

async function renderTutorSupport(env, user) {
  const tickets = await env.DB.prepare("SELECT * FROM support_tickets WHERE user_id = ? ORDER BY updated_at DESC").bind(user.id).all();
  const ticketList = tickets.results || [];
  const statusBadge = (s) => {
    if (s === "open") return '<span class="p-badge p-badge-yellow">Open</span>';
    if (s === "in_progress") return '<span class="p-badge p-badge-blue">In Progress</span>';
    if (s === "resolved") return '<span class="p-badge p-badge-green">Resolved</span>';
    return '<span class="p-badge p-badge-gray">Closed</span>';
  };
  const ticketsHtml = ticketList.length > 0 ? ticketList.map(t => `<a href="/tutor/support/${t.id}" class="p-ticket-card">
    <div><div class="p-ticket-subject">${escapeHtml(t.subject)}</div><div class="p-ticket-date">${new Date(t.created_at).toLocaleDateString()}</div></div>
    <div>${statusBadge(t.status)}</div>
  </a>`).join("") : '<div class="p-empty"><div class="p-empty-icon">&#128172;</div><p>No tickets yet</p></div>';
  const content = `
    <div class="p-card" style="margin-bottom:24px">
      <div class="p-card-title">New Support Ticket</div>
      <form id="ticketForm">
        <div class="p-form-group"><label class="p-form-label">Subject</label><input class="p-form-input" name="subject" required placeholder="What do you need help with?"></div>
        <div class="p-form-group"><label class="p-form-label">Message</label><textarea class="p-form-input p-form-textarea" name="message" required placeholder="Describe your issue..."></textarea></div>
        <button type="submit" class="p-btn p-btn-primary" style="background:#2563EB">Submit Ticket</button>
      </form>
    </div>
    <div class="p-card-title">My Tickets</div>
    ${ticketsHtml}
    <script>
    document.getElementById('ticketForm').addEventListener('submit', async function(e) {
      e.preventDefault();
      const fd = new FormData(this);
      const data = Object.fromEntries(fd.entries());
      const res = await fetch('/api/tutor/support', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(data) });
      const json = await res.json();
      if (json.success) location.reload(); else alert(json.error || 'Failed');
    });
    <\/script>
  `;
  return htmlTutorPage({ title: "Support", pageTitle: "Support", activePage: "support", content, userName: `${user.prenom} ${user.nom}` });
}
__name(renderTutorSupport, "renderTutorSupport");

async function renderTutorTicketDetail(env, user, ticketId) {
  const ticket = await env.DB.prepare("SELECT * FROM support_tickets WHERE id = ? AND user_id = ?").bind(ticketId, user.id).first();
  if (!ticket) return null;
  const responses = await env.DB.prepare("SELECT tr.*, u.prenom, u.nom FROM ticket_responses tr JOIN users u ON u.id = tr.user_id WHERE tr.ticket_id = ? ORDER BY tr.created_at ASC").bind(ticketId).all();
  const msgs = responses.results || [];
  const statusBadge = (s) => {
    if (s === "open") return '<span class="p-badge p-badge-yellow">Open</span>';
    if (s === "in_progress") return '<span class="p-badge p-badge-blue">In Progress</span>';
    if (s === "resolved") return '<span class="p-badge p-badge-green">Resolved</span>';
    return '<span class="p-badge p-badge-gray">Closed</span>';
  };
  const msgsHtml = msgs.map(m => `<div class="p-msg ${m.user_role === 'admin' ? 'p-msg-admin' : 'p-msg-student'}">
    <div style="font-size:14px">${escapeHtml(m.message)}</div>
    <div class="p-msg-meta">${escapeHtml(m.prenom || "")} ${escapeHtml(m.nom || "")} &bull; ${new Date(m.created_at).toLocaleString()}</div>
  </div>`).join("");
  const content = `
    <a href="/tutor/support" class="p-btn p-btn-secondary" style="margin-bottom:16px">&#8592; Back to Tickets</a>
    <div class="p-card" style="margin-bottom:16px">
      <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
        <h3 style="font-size:18px;font-weight:700">${escapeHtml(ticket.subject)}</h3>
        ${statusBadge(ticket.status)}
      </div>
      <p style="color:#64748B;font-size:14px;margin-top:8px">${escapeHtml(ticket.message)}</p>
      <div style="color:#94A3B8;font-size:12px;margin-top:8px">Created: ${new Date(ticket.created_at).toLocaleString()}</div>
    </div>
    <div class="p-card-title">Conversation</div>
    ${msgsHtml || '<div class="p-empty" style="padding:24px"><p>No replies yet</p></div>'}
    ${ticket.status !== 'closed' ? '<div class="p-card" style="margin-top:16px"><form id="replyForm"><div class="p-form-group"><textarea class="p-form-input p-form-textarea" name="message" required placeholder="Type your reply..."></textarea></div><button type="submit" class="p-btn p-btn-primary">Send Reply</button></form></div>' : ''}
    <script>
    var replyForm = document.getElementById('replyForm');
    if (replyForm) replyForm.addEventListener('submit', async function(e) {
      e.preventDefault();
      const fd = new FormData(this);
      const res = await fetch('/api/tutor/support/${ticketId}/reply', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ message: fd.get('message') }) });
      const json = await res.json();
      if (json.success) location.reload(); else alert(json.error || 'Failed');
    });
    <\/script>
  `;
  return htmlTutorPage({ title: ticket.subject, pageTitle: "Ticket Detail", activePage: "support", content, userName: `${user.prenom} ${user.nom}` });
}
__name(renderTutorTicketDetail, "renderTutorTicketDetail");

