async function handlePortalProfileUpdate(request, env, user) {
  const data = await request.json();
  const updates = [];
  const values = [];
  const fields = ["prenom", "nom", "telephone", "address", "education", "gender", "date_of_birth", "city", "country", "postal_code"];
  fields.forEach(f => { if (data[f] !== undefined) { updates.push(f + " = ?"); values.push(typeof data[f] === "string" ? data[f].trim() : data[f]); } });
  if (updates.length === 0) return errorResponse("No changes");
  updates.push("updated_at = datetime('now')");
  values.push(user.id);
  await env.DB.prepare("UPDATE users SET " + updates.join(", ") + " WHERE id = ?").bind(...values).run();
  return jsonResponse({ success: true });
}
__name(handlePortalProfileUpdate, "handlePortalProfileUpdate");

async function handleTutorProfileUpdate(request, env, user) {
  const data = await request.json();
  // Update users table for shared fields
  const userUpdates = [];
  const userValues = [];
  ["prenom", "nom", "telephone", "gender", "date_of_birth"].forEach(f => {
    if (data[f] !== undefined) { userUpdates.push(f + " = ?"); userValues.push(typeof data[f] === "string" ? data[f].trim() : data[f]); }
  });
  if (userUpdates.length > 0) {
    userUpdates.push("updated_at = datetime('now')");
    userValues.push(user.id);
    await env.DB.prepare("UPDATE users SET " + userUpdates.join(", ") + " WHERE id = ?").bind(...userValues).run();
  }
  // Update formateurs table for tutor-specific fields
  if (user.formateur_id) {
    const fmtUpdates = [];
    const fmtValues = [];
    ["prenom", "nom", "telephone", "bio", "specialisations", "ville", "code_postal", "country"].forEach(f => {
      if (data[f] !== undefined) { fmtUpdates.push(f + " = ?"); fmtValues.push(typeof data[f] === "string" ? data[f].trim() : data[f]); }
    });
    if (fmtUpdates.length > 0) {
      fmtUpdates.push("updated_at = datetime('now')");
      fmtValues.push(user.formateur_id);
      await env.DB.prepare("UPDATE formateurs SET " + fmtUpdates.join(", ") + " WHERE id = ?").bind(...fmtValues).run();
    }
  }
  return jsonResponse({ success: true });
}
__name(handleTutorProfileUpdate, "handleTutorProfileUpdate");

async function handlePasswordChange(request, env, user) {
  const data = await request.json();
  if (!data.current_password || !data.new_password) return errorResponse("Missing fields");
  if (data.new_password.length < 8) return errorResponse("Password must be at least 8 characters");
  const fullUser = await env.DB.prepare("SELECT password_hash FROM users WHERE id = ?").bind(user.id).first();
  if (!fullUser) return errorResponse("User not found", 404);
  const valid = await verifyPassword(data.current_password, fullUser.password_hash);
  if (!valid) return errorResponse("Current password is incorrect");
  const newHash = await hashPassword(data.new_password);
  await env.DB.prepare("UPDATE users SET password_hash = ?, updated_at = datetime('now') WHERE id = ?").bind(newHash, user.id).run();
  return jsonResponse({ success: true });
}
__name(handlePasswordChange, "handlePasswordChange");

async function handleCreateTicket(request, env, user) {
  const data = await request.json();
  if (!data.subject || !data.message) return errorResponse("Subject and message are required");
  const id = generateId();
  await env.DB.prepare(
    "INSERT INTO support_tickets (id, user_id, subject, message) VALUES (?, ?, ?, ?)"
  ).bind(id, user.id, data.subject.trim(), data.message.trim()).run();
  return jsonResponse({ success: true, id });
}
__name(handleCreateTicket, "handleCreateTicket");

async function handleTicketReply(request, env, user, ticketId) {
  const data = await request.json();
  if (!data.message) return errorResponse("Message is required");
  const ticket = await env.DB.prepare("SELECT id, user_id FROM support_tickets WHERE id = ?").bind(ticketId).first();
  if (!ticket) return errorResponse("Ticket not found", 404);
  if (ticket.user_id !== user.id && user.role !== "admin") return errorResponse("Unauthorized", 403);
  const id = generateId();
  await env.DB.prepare(
    "INSERT INTO ticket_responses (id, ticket_id, user_id, user_role, message) VALUES (?, ?, ?, ?, ?)"
  ).bind(id, ticketId, user.id, user.role, data.message.trim()).run();
  await env.DB.prepare("UPDATE support_tickets SET updated_at = datetime('now') WHERE id = ?").bind(ticketId).run();
  return jsonResponse({ success: true });
}
__name(handleTicketReply, "handleTicketReply");

