// --- Serve user file (student photo/document) ---
async function serveUserFile(env, userId, type) {
  const validTypes = ["photo", "doc_identite", "doc_diplome"];
  if (!validTypes.includes(type)) return errorResponse("Invalid type", 400);
  const col = type === "photo" ? "photo_url" : type + "_url";
  const user = await env.DB.prepare("SELECT " + col + " FROM users WHERE id = ?").bind(userId).first();
  if (!user || !user[col]) return errorResponse("File not found", 404);
  const obj = await env.R2.get(user[col]);
  if (!obj) return errorResponse("File not found in storage", 404);
  const headers = new Headers();
  headers.set("Content-Type", obj.httpMetadata?.contentType || "application/octet-stream");
  headers.set("Cache-Control", "private, max-age=3600");
  return new Response(obj.body, { headers });
}
