async function handleNotificationsUpdate(request, env, user) {
  const data = await request.json();
  const updates = [];
  const values = [];
  ["notif_sms_lessons", "notif_email_activity", "notif_email_lessons", "notif_email_offers", "notif_email_newsletter"].forEach(f => {
    if (data[f] !== undefined) { updates.push(f + " = ?"); values.push(data[f] ? 1 : 0); }
  });
  if (updates.length === 0) return errorResponse("No changes");
  updates.push("updated_at = datetime('now')");
  values.push(user.id);
  await env.DB.prepare("UPDATE users SET " + updates.join(", ") + " WHERE id = ?").bind(...values).run();
  return jsonResponse({ success: true });
}
